import {
  ChangeDetectorRef,
  Component,
  OnInit,
  TemplateRef,
  ViewChild
} from '@angular/core';
import {
  DataTableCellContext,
  ConditionalStyle,
  DataTableColumn,
  DataTableExpandEvent,
  DataTableExpandableContext,
  DataTablePageEvent,
  DataTableRowsPerPageEvent,
  DataTableSelectionState,
  DataTableSortEvent
} from '@revivejs/angular-data-table-component';

type Movie = {
  id: number;
  title: string;
  director: string;
  year: number;
  genre: string;
  rating: number;
  status: 'stable' | 'review' | 'critical';
  budget: number;
  summary: string;
};

type Ticket = {
  id: number;
  team: string;
  region: string;
  agent: string;
  priority: 'low' | 'medium' | 'high';
  age: number;
  status: 'open' | 'pending' | 'resolved';
};

const INSTALL_CODE = 'npm install @revivejs/angular-data-table-component';

const SETUP_CODE = `import { DataTableModule } from '@revivejs/angular-data-table-component';\n\n@NgModule({\n  imports: [BrowserModule, DataTableModule]\n})\nexport class AppModule {}`;

const BASIC_CODE = `<revive-data-table\n  [columns]="basicColumns"\n  [data]="movies"\n  [pagination]="true">\n</revive-data-table>`;

const SELECTION_CODE = `<revive-data-table\n  [columns]="selectableColumns"\n  [data]="movies"\n  [selectableRows]="true"\n  (selectedRowsChange)="handleSelection($event)">\n</revive-data-table>`;

const EXPANSION_CODE = `<revive-data-table\n  [columns]="customColumns"\n  [data]="movies"\n  [expandableRows]="true"\n  [expandableRowTemplate]="movieDetailTemplate">\n</revive-data-table>`;

const SERVER_CODE = `<revive-data-table\n  [columns]="serverColumns"\n  [data]="serverRows"\n  [pagination]="true"\n  [paginationServer]="true"\n  [paginationTotalRows]="allTickets.length"\n  (pageChange)="handleServerPage($event)">\n</revive-data-table>`;

function stamp(message: string) {
  return `${new Date().toLocaleTimeString('en-US', { hour12: false })}  ${message}`;
}

function buildMovies(): Movie[] {
  return [
    {
      id: 1,
      title: 'Arrival',
      director: 'Denis Villeneuve',
      year: 2016,
      genre: 'Sci-Fi',
      rating: 8.1,
      status: 'stable',
      budget: 47000000,
      summary: 'A linguist is recruited to decode an alien language before global panic wins.'
    },
    {
      id: 2,
      title: 'Moonlight',
      director: 'Barry Jenkins',
      year: 2016,
      genre: 'Drama',
      rating: 7.4,
      status: 'review',
      budget: 1500000,
      summary: 'A three-part portrait of identity, vulnerability, and adulthood.'
    },
    {
      id: 3,
      title: 'Mad Max: Fury Road',
      director: 'George Miller',
      year: 2015,
      genre: 'Action',
      rating: 8.1,
      status: 'stable',
      budget: 150000000,
      summary: 'A relentless desert chase powered by practical effects and chaos.'
    },
    {
      id: 4,
      title: 'Annihilation',
      director: 'Alex Garland',
      year: 2018,
      genre: 'Sci-Fi',
      rating: 6.8,
      status: 'critical',
      budget: 40000000,
      summary: 'A biologist enters a shifting zone where nature mutates beyond recognition.'
    },
    {
      id: 5,
      title: 'Whiplash',
      director: 'Damien Chazelle',
      year: 2014,
      genre: 'Drama',
      rating: 8.5,
      status: 'stable',
      budget: 3300000,
      summary: 'A young drummer collides with an unforgiving mentor.'
    },
    {
      id: 6,
      title: 'Everything Everywhere All at Once',
      director: 'Daniels',
      year: 2022,
      genre: 'Fantasy',
      rating: 7.8,
      status: 'review',
      budget: 25000000,
      summary: 'Multiverse absurdity, family pressure, and empathy on maximalist settings.'
    },
    {
      id: 7,
      title: 'The Farewell',
      director: 'Lulu Wang',
      year: 2019,
      genre: 'Comedy',
      rating: 7.5,
      status: 'stable',
      budget: 3000000,
      summary: 'A family stages a fake wedding to say goodbye without saying goodbye.'
    },
    {
      id: 8,
      title: 'Parasite',
      director: 'Bong Joon-ho',
      year: 2019,
      genre: 'Thriller',
      rating: 8.5,
      status: 'stable',
      budget: 11400000,
      summary: 'Class satire escalates into a razor-sharp thriller.'
    },
    {
      id: 9,
      title: 'Aftersun',
      director: 'Charlotte Wells',
      year: 2022,
      genre: 'Drama',
      rating: 7.6,
      status: 'review',
      budget: 2000000,
      summary: 'A holiday memory shifts into a meditation on grief and perspective.'
    },
    {
      id: 10,
      title: 'Oppenheimer',
      director: 'Christopher Nolan',
      year: 2023,
      genre: 'History',
      rating: 8.3,
      status: 'stable',
      budget: 100000000,
      summary: 'A dense character-driven story about ambition, fear, and consequence.'
    },
    {
      id: 11,
      title: 'Past Lives',
      director: 'Celine Song',
      year: 2023,
      genre: 'Romance',
      rating: 7.9,
      status: 'stable',
      budget: 12000000,
      summary: 'Two lives stay connected across years, borders, and decisions.'
    },
    {
      id: 12,
      title: 'Tenet',
      director: 'Christopher Nolan',
      year: 2020,
      genre: 'Sci-Fi',
      rating: 7.3,
      status: 'critical',
      budget: 205000000,
      summary: 'Time inversion delivers spectacle and confusion in equal measure.'
    }
  ];
}

function buildTickets(): Ticket[] {
  const priorities: Ticket['priority'][] = ['low', 'medium', 'high'];
  const statuses: Ticket['status'][] = ['open', 'pending', 'resolved'];
  const teams = ['Platform', 'Billing', 'Delivery', 'Identity'];
  const regions = ['NA', 'EU', 'LATAM', 'APAC'];
  const agents = ['Lena', 'Marco', 'Priya', 'Jon', 'Ari', 'Sara'];
  const rows: Ticket[] = [];

  for (let index = 0; index < 42; index += 1) {
    rows.push({
      id: index + 1,
      team: teams[index % teams.length],
      region: regions[index % regions.length],
      agent: agents[index % agents.length],
      priority: priorities[index % priorities.length],
      age: 1 + (index * 3) % 24,
      status: statuses[index % statuses.length]
    });
  }

  return rows;
}

@Component({
  selector: 'docs-root',
  standalone: false,
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.css']
})
export class AppComponent implements OnInit {
  @ViewChild('searchTools', { static: true }) searchTools!: TemplateRef<unknown>;
  @ViewChild('statusCell', { static: true }) statusCell!: TemplateRef<DataTableCellContext<Movie>>;
  @ViewChild('budgetCell', { static: true }) budgetCell!: TemplateRef<DataTableCellContext<Movie>>;
  @ViewChild('movieDetail', { static: true }) movieDetail!: TemplateRef<DataTableExpandableContext<Movie>>;

  readonly installCode = INSTALL_CODE;
  readonly setupCode = SETUP_CODE;
  readonly basicCode = BASIC_CODE;
  readonly selectionCode = SELECTION_CODE;
  readonly expansionCode = EXPANSION_CODE;
  readonly serverCode = SERVER_CODE;

  readonly movies = buildMovies();
  readonly allTickets = buildTickets();

  readonly logEntries: string[] = [];

  readonly contextualStyles: ConditionalStyle<Movie>[] = [
    {
      when: (row) => row.status === 'critical',
      style: {
        borderLeft: '4px solid #b42318',
        background: 'rgba(180, 35, 24, 0.06)'
      }
    },
    {
      when: (row) => row.status === 'review',
      style: {
        borderLeft: '4px solid #d26a2a',
        background: 'rgba(210, 106, 42, 0.06)'
      }
    }
  ];

  basicColumns: DataTableColumn<Movie>[] = [];
  sortableColumns: DataTableColumn<Movie>[] = [];
  selectableColumns: DataTableColumn<Movie>[] = [];
  customColumns: DataTableColumn<Movie>[] = [];
  compactColumns: DataTableColumn<Movie>[] = [];
  serverColumns: DataTableColumn<Ticket>[] = [];

  searchTerm = '';
  selectionSummary = 'No rows selected yet.';

  serverPage = 1;
  serverRowsPerPage = 5;
  serverLoading = false;
  serverRows: Ticket[] = [];

  constructor(private readonly changeDetectorRef: ChangeDetectorRef) {}

  ngOnInit() {
    this.basicColumns = this.createBasicColumns();
    this.sortableColumns = this.createSortableColumns();
    this.selectableColumns = this.createSelectableColumns();
    this.customColumns = this.createCustomColumns();
    this.compactColumns = this.createCompactColumns();
    this.serverColumns = this.createServerColumns();
    this.refreshServerRows();

    this.pushLog('Demo loaded successfully.');
    this.changeDetectorRef.detectChanges();
  }

  get filteredMovies() {
    const term = this.searchTerm.trim().toLowerCase();

    if (!term) {
      return this.movies;
    }

    return this.movies.filter((movie) =>
      [movie.title, movie.director, movie.genre, movie.status]
        .join(' ')
        .toLowerCase()
        .includes(term)
    );
  }

  pushLog(message: string) {
    this.logEntries.unshift(stamp(message));
    this.logEntries.splice(14);
  }

  clearLog() {
    this.logEntries.splice(0, this.logEntries.length);
  }

  onSearchTermChange(term: string) {
    this.searchTerm = term;
    this.pushLog(`Search term changed to "${term || 'all'}".`);
  }

  onSort(label: string, event: DataTableSortEvent<Movie | Ticket>) {
    this.pushLog(`${label}: sorted by ${String(event.column.name)} (${event.direction}).`);
  }

  onSelectionChange(state: DataTableSelectionState<Movie>) {
    this.selectionSummary =
      state.selectedCount === 0
        ? 'No rows selected yet.'
        : `${state.selectedCount} row(s) selected: ${state.selectedRows
            .map((row) => row.title)
            .join(', ')}.`;

    this.pushLog(`Selection updated: ${state.selectedCount} row(s).`);
  }

  onExpand(event: DataTableExpandEvent<Movie>) {
    this.pushLog(`${event.expanded ? 'Expanded' : 'Collapsed'} "${event.row.title}".`);
  }

  onPage(event: DataTablePageEvent) {
    this.pushLog(`Client pagination moved to page ${event.page}.`);
  }

  onRowsPerPage(event: DataTableRowsPerPageEvent) {
    this.pushLog(`Rows per page changed to ${event.rowsPerPage}.`);
  }

  onRowClick(row: Movie) {
    this.pushLog(`Row clicked: ${row.title}.`);
  }

  onServerPage(event: DataTablePageEvent) {
    this.serverPage = event.page;
    this.serverLoading = true;
    this.pushLog(`Server page requested: ${event.page}.`);

    setTimeout(() => {
      this.serverLoading = false;
      this.refreshServerRows();
    }, 220);
  }

  onServerRowsPerPage(event: DataTableRowsPerPageEvent) {
    this.serverRowsPerPage = event.rowsPerPage;
    this.serverPage = 1;
    this.serverLoading = true;
    this.pushLog(`Server page size changed to ${event.rowsPerPage}.`);

    setTimeout(() => {
      this.serverLoading = false;
      this.refreshServerRows();
    }, 220);
  }

  statusTone(status: Movie['status']) {
    switch (status) {
      case 'stable':
        return 'stable';
      case 'review':
        return 'review';
      default:
        return 'critical';
    }
  }

  priorityTone(priority: Ticket['priority']) {
    switch (priority) {
      case 'low':
        return 'low';
      case 'medium':
        return 'medium';
      default:
        return 'high';
    }
  }

  formatMoney(value: number) {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
      notation: 'compact',
      maximumFractionDigits: 1
    }).format(value);
  }

  private refreshServerRows() {
    const start = (this.serverPage - 1) * this.serverRowsPerPage;
    this.serverRows = this.allTickets.slice(start, start + this.serverRowsPerPage);
    this.pushLog(`Server rows refreshed for page ${this.serverPage}.`);
  }

  private createBasicColumns(): DataTableColumn<Movie>[] {
    return [
      {
        id: 'title',
        name: 'Title',
        selector: (row) => row.title,
        sortable: true,
        wrap: true,
        minWidth: '220px'
      },
      {
        id: 'director',
        name: 'Director',
        selector: (row) => row.director,
        sortable: true
      },
      {
        id: 'year',
        name: 'Year',
        selector: (row) => row.year,
        sortable: true,
        right: true,
        width: '100px'
      }
    ];
  }

  private createSortableColumns(): DataTableColumn<Movie>[] {
    return [
      ...this.createBasicColumns(),
      {
        id: 'genre',
        name: 'Genre',
        selector: (row) => row.genre,
        sortable: true,
        width: '120px'
      },
      {
        id: 'rating',
        name: 'Rating',
        selector: (row) => row.rating,
        sortable: true,
        right: true,
        width: '110px'
      }
    ];
  }

  private createSelectableColumns(): DataTableColumn<Movie>[] {
    return [
      {
        id: 'title',
        name: 'Title',
        selector: (row) => row.title,
        sortable: true,
        wrap: true
      },
      {
        id: 'status',
        name: 'Status',
        selector: (row) => row.status,
        sortable: true,
        width: '120px'
      },
      {
        id: 'rating',
        name: 'Rating',
        selector: (row) => row.rating,
        sortable: true,
        right: true,
        width: '100px'
      }
    ];
  }

  private createCustomColumns(): DataTableColumn<Movie>[] {
    return [
      {
        id: 'title',
        name: 'Title',
        selector: (row) => row.title,
        sortable: true,
        wrap: true,
        minWidth: '220px'
      },
      {
        id: 'status',
        name: 'Status',
        selector: (row) => row.status,
        sortable: true,
        width: '130px',
        cellTemplate: this.statusCell
      },
      {
        id: 'budget',
        name: 'Budget',
        selector: (row) => row.budget,
        sortable: true,
        right: true,
        width: '120px',
        cellTemplate: this.budgetCell
      },
      {
        id: 'summary',
        name: 'Summary',
        selector: (row) => row.summary,
        wrap: true
      }
    ];
  }

  private createCompactColumns(): DataTableColumn<Movie>[] {
    return [
      {
        id: 'title',
        name: 'Title',
        selector: (row) => row.title,
        sortable: true,
        wrap: true,
        minWidth: '220px'
      },
      {
        id: 'genre',
        name: 'Genre',
        selector: (row) => row.genre,
        sortable: true,
        width: '120px'
      },
      {
        id: 'status',
        name: 'Status',
        selector: (row) => row.status,
        sortable: true,
        width: '120px'
      },
      {
        id: 'year',
        name: 'Year',
        selector: (row) => row.year,
        sortable: true,
        width: '100px',
        right: true
      }
    ];
  }

  private createServerColumns(): DataTableColumn<Ticket>[] {
    return [
      {
        id: 'team',
        name: 'Team',
        selector: (row) => row.team,
        sortable: true
      },
      {
        id: 'region',
        name: 'Region',
        selector: (row) => row.region,
        sortable: true,
        width: '100px'
      },
      {
        id: 'agent',
        name: 'Agent',
        selector: (row) => row.agent,
        sortable: true
      },
      {
        id: 'priority',
        name: 'Priority',
        selector: (row) => row.priority,
        sortable: true,
        width: '110px'
      },
      {
        id: 'status',
        name: 'Status',
        selector: (row) => row.status,
        sortable: true,
        width: '110px'
      },
      {
        id: 'age',
        name: 'Age (h)',
        selector: (row) => row.age,
        sortable: true,
        right: true,
        width: '100px'
      }
    ];
  }
}
<div class="shell">
  <section class="hero">
    <div class="hero-card hero-main">
      <span class="badge">ANGULAR 20.3 · DATA TABLE</span>
      <h1>&#64;revivejs/angular-data-table-component</h1>
      <p>
        A community-style Angular data table component with sorting, row selection, expandable
        content, client or server pagination, conditional styles, and a demo layout that tracks
        the Angular release line.
      </p>
      <div class="feature-grid">
        <div class="feature">
          <strong>Declarative columns</strong>
          Keep column definitions in TypeScript and let Angular templates handle the rich cells.
        </div>
        <div class="feature">
          <strong>Native Angular patterns</strong>
          Custom cells and expanded content use <code>TemplateRef</code>, not framework adapters.
        </div>
        <div class="feature">
          <strong>Stateful table UX</strong>
          Sorting, pagination, selection, and expandable rows are available out of the box.
        </div>
        <div class="feature">
          <strong>Versioned docs</strong>
          This repository follows the Angular major line with a dedicated docs build per version.
        </div>
      </div>
      <div class="cta-row">
        <a class="btn" href="#demos">See demos</a>
        <a
          class="btn secondary"
          href="https://github.com/alexandroit/angular-data-table-component#readme"
          target="_blank"
          rel="noreferrer">
          README
        </a>
      </div>
    </div>

    <div class="hero-card hero-setup">
      <h2>Setup in 3 steps</h2>

      <div class="step">
        <span class="step-num">1</span>
        <div>
          <strong>Install</strong>
          <pre>{{ installCode }}</pre>
        </div>
      </div>

      <div class="step">
        <span class="step-num">2</span>
        <div>
          <strong>Register the module</strong>
          <pre>{{ setupCode }}</pre>
        </div>
      </div>

      <div class="step">
        <span class="step-num">3</span>
        <div>
          <strong>Render the table</strong>
          <pre>{{ basicCode }}</pre>
        </div>
      </div>
    </div>
  </section>

  <section class="layout" id="demos">
    <div class="panels">
      <article class="panel">
        <div class="panel-header">
          <h2>Core — basic usage</h2>
          <p>
            Start with declarative columns and rows, then turn on the features you need with
            inputs instead of rebuilding the table structure.
          </p>
        </div>
        <div class="demo-grid">
          <section class="demo-card">
            <h3>Basic table</h3>
            <p>A minimal setup with sorting-ready columns and client pagination.</p>
            <pre class="code">{{ basicCode }}</pre>
            <div class="table-frame">
              <revive-data-table
                title="Film catalog"
                [columns]="basicColumns"
                [data]="movies"
                [pagination]="true"
                (rowClicked)="onRowClick($event)">
              </revive-data-table>
            </div>
          </section>

          <section class="demo-card">
            <h3>Sorting and search tools</h3>
            <p>
              Keep sorting in the table and search in your component state through a sub-header
              template.
            </p>
            <pre class="code">{{ basicCode }}</pre>
            <div class="table-frame">
              <revive-data-table
                title="Searchable releases"
                [columns]="sortableColumns"
                [data]="filteredMovies"
                [pagination]="true"
                [subHeader]="true"
                [subHeaderTemplate]="searchTools"
                (sortChange)="onSort('Searchable table', $event)"
                (pageChange)="onPage($event)"
                (rowsPerPageChange)="onRowsPerPage($event)">
              </revive-data-table>
            </div>
          </section>
        </div>
      </article>

      <article class="panel">
        <div class="panel-header">
          <h2>Selection and row events</h2>
          <p>
            The component emits selection state and row interaction events in a predictable Angular
            shape.
          </p>
        </div>
        <div class="demo-grid">
          <section class="demo-card">
            <h3>Selectable rows</h3>
            <p>Turn on multi-select and keep the selected rows summary in component state.</p>
            <pre class="code">{{ selectionCode }}</pre>
            <div class="table-frame">
              <revive-data-table
                title="Review queue"
                [columns]="selectableColumns"
                [data]="movies"
                [selectableRows]="true"
                [selectableRowsHighlight]="true"
                [pagination]="true"
                (selectedRowsChange)="onSelectionChange($event)"
                (sortChange)="onSort('Selection table', $event)">
              </revive-data-table>
            </div>
            <p class="note">{{ selectionSummary }}</p>
          </section>

          <section class="demo-card">
            <h3>Single selection mode</h3>
            <p>Use radio-style selection when only one active record should be chosen.</p>
            <pre class="code">[selectableRowsSingle]=\"true\"</pre>
            <div class="table-frame">
              <revive-data-table
                title="Primary pick"
                [columns]="selectableColumns"
                [data]="movies"
                [selectableRows]="true"
                [selectableRowsSingle]="true"
                [pagination]="true"
                (selectedRowsChange)="onSelectionChange($event)">
              </revive-data-table>
            </div>
          </section>
        </div>
      </article>

      <article class="panel">
        <div class="panel-header">
          <h2>Custom cells and expandable rows</h2>
          <p>
            Angular templates are first-class here. Use template refs for richer cells and expanded
            content instead of rebuilding the table component.
          </p>
        </div>
        <div class="demo-grid">
          <section class="demo-card">
            <h3>Template-driven cells</h3>
            <p>Status pills, compact currency blocks, and wrapped summaries all stay declarative.</p>
            <pre class="code">{{ expansionCode }}</pre>
            <div class="table-frame">
              <revive-data-table
                title="Editorial cuts"
                [columns]="customColumns"
                [data]="movies"
                [expandableRows]="true"
                [expandableRowTemplate]="movieDetail"
                [conditionalRowStyles]="contextualStyles"
                [pagination]="true"
                [highlightOnHover]="true"
                [pointerOnHover]="true"
                (rowExpandToggled)="onExpand($event)"
                (rowClicked)="onRowClick($event)">
              </revive-data-table>
            </div>
          </section>

          <section class="demo-card">
            <h3>Dark theme + dense + fixed header</h3>
            <p>
              The built-in dark theme stays readable and works with dense rows and sticky headers.
            </p>
            <pre class="code">theme=\"dark\" [dense]=\"true\" [fixedHeader]=\"true\"</pre>
            <div class="table-frame dark-frame">
              <revive-data-table
                title="Compact monitoring board"
                theme="dark"
                [columns]="compactColumns"
                [data]="movies"
                [pagination]="true"
                [dense]="true"
                [fixedHeader]="true"
                fixedHeaderScrollHeight="280px"
                [striped]="true"
                [highlightOnHover]="true"
                (sortChange)="onSort('Dark table', $event)">
              </revive-data-table>
            </div>
          </section>
        </div>
      </article>

      <article class="panel">
        <div class="panel-header">
          <h2>Server-style pagination</h2>
          <p>
            When you set <code>paginationServer</code>, the component stops slicing rows internally
            and lets your container load the current page from an API.
          </p>
        </div>
        <div class="demo-grid">
          <section class="demo-card">
            <h3>Remote page simulation</h3>
            <p>
              This demo simulates a remote API by slicing data after a short delay while keeping the
              table footer fully interactive.
            </p>
            <pre class="code">{{ serverCode }}</pre>
            <div class="table-frame">
              <revive-data-table
                title="Support tickets"
                [columns]="serverColumns"
                [data]="serverRows"
                [pagination]="true"
                [paginationServer]="true"
                [paginationDefaultPage]="serverPage"
                [paginationPerPage]="serverRowsPerPage"
                [paginationTotalRows]="allTickets.length"
                [progressPending]="serverLoading"
                (pageChange)="onServerPage($event)"
                (rowsPerPageChange)="onServerRowsPerPage($event)"
                (sortChange)="onSort('Server table', $event)">
              </revive-data-table>
            </div>
          </section>
        </div>
      </article>

      <article class="panel ref-panel">
        <div class="panel-header">
          <h2>Quick API reference</h2>
        </div>
        <div class="ref-grid">
          <div class="ref-card">
            <h4>Component inputs</h4>
            <table class="api-table">
              <thead>
                <tr>
                  <th>Input</th>
                  <th>Description</th>
                </tr>
              </thead>
              <tbody>
                <tr><td><code>columns</code></td><td>Declarative column definitions with selectors, sorting, and templates.</td></tr>
                <tr><td><code>data</code></td><td>Row data to render.</td></tr>
                <tr><td><code>selectableRows</code></td><td>Enables row selection.</td></tr>
                <tr><td><code>expandableRows</code></td><td>Enables expandable detail rows.</td></tr>
                <tr><td><code>expandableRowTemplate</code></td><td>Angular template used for expanded content.</td></tr>
                <tr><td><code>pagination</code></td><td>Turns on built-in pagination UI.</td></tr>
                <tr><td><code>paginationServer</code></td><td>Lets the container control which rows are currently loaded.</td></tr>
                <tr><td><code>conditionalRowStyles</code></td><td>Applies row styles when predicates match.</td></tr>
                <tr><td><code>theme</code></td><td>Switch between the <code>default</code> and <code>dark</code> themes.</td></tr>
              </tbody>
            </table>
          </div>

          <div class="ref-card">
            <h4>Column capabilities</h4>
            <table class="api-table">
              <thead>
                <tr>
                  <th>Field</th>
                  <th>Description</th>
                </tr>
              </thead>
              <tbody>
                <tr><td><code>selector</code></td><td>Read values with a row function or a property key.</td></tr>
                <tr><td><code>format</code></td><td>Return custom display values before rendering.</td></tr>
                <tr><td><code>cellTemplate</code></td><td>Use an Angular template for richer cell layouts.</td></tr>
                <tr><td><code>sortable</code></td><td>Turns on built-in sorting for that column.</td></tr>
                <tr><td><code>sortFunction</code></td><td>Override the comparison logic for a specific column.</td></tr>
              </tbody>
            </table>
          </div>

          <div class="ref-card">
            <h4>Outputs</h4>
            <table class="api-table">
              <thead>
                <tr>
                  <th>Output</th>
                  <th>Description</th>
                </tr>
              </thead>
              <tbody>
                <tr><td><code>sortChange</code></td><td>Fires with the current column, direction, and visible rows.</td></tr>
                <tr><td><code>selectedRowsChange</code></td><td>Returns the selection state and selected rows array.</td></tr>
                <tr><td><code>pageChange</code></td><td>Fires when the current page changes.</td></tr>
                <tr><td><code>rowsPerPageChange</code></td><td>Fires when the footer page size changes.</td></tr>
                <tr><td><code>rowClicked</code></td><td>Fires with the clicked row.</td></tr>
                <tr><td><code>rowExpandToggled</code></td><td>Fires when an expandable row opens or closes.</td></tr>
              </tbody>
            </table>
          </div>
        </div>
      </article>
    </div>

    <aside class="log-panel">
      <h2>Event Log</h2>
      <p>Interact with the demos to see Angular output events and table state changes here.</p>
      <div class="log-controls">
        <button class="ghost small" (click)="clearLog()">Clear</button>
      </div>
      <div class="log-list">
        <div *ngFor="let entry of logEntries" class="log-entry">
          {{ entry }}
        </div>
      </div>
    </aside>
  </section>

  <footer class="footer">
    <p>
      <strong>&#64;revivejs/angular-data-table-component</strong> keeps the table API declarative and
      close to Angular templates, while still covering the everyday behavior people expect from a
      modern data grid.
    </p>
  </footer>

  <ng-template #searchTools>
    <div class="toolbar">
      <input
        [ngModel]="searchTerm"
        (ngModelChange)="onSearchTermChange($event)"
        type="search"
        placeholder="Filter by title, director, genre or status" />
      <span class="toolbar-tip">Client-side filtering in the host component.</span>
    </div>
  </ng-template>

  <ng-template #statusCell let-row let-value="value">
    <span class="status-pill" [ngClass]="statusTone(row.status)">
      {{ value }}
    </span>
  </ng-template>

  <ng-template #budgetCell let-row>
    <div class="metric-stack">
      <strong>{{ formatMoney(row.budget) }}</strong>
      <span>production</span>
    </div>
  </ng-template>

  <ng-template #movieDetail let-row>
    <div class="detail-grid">
      <div>
        <span class="detail-label">Director</span>
        <strong>{{ row.director }}</strong>
      </div>
      <div>
        <span class="detail-label">Genre</span>
        <strong>{{ row.genre }}</strong>
      </div>
      <div>
        <span class="detail-label">Rating</span>
        <strong>{{ row.rating }}/10</strong>
      </div>
      <div>
        <span class="detail-label">Budget</span>
        <strong>{{ formatMoney(row.budget) }}</strong>
      </div>
      <div class="detail-summary">
        <span class="detail-label">Summary</span>
        <p>{{ row.summary }}</p>
      </div>
    </div>
  </ng-template>
</div>
